B.HR=new A.f1("Duration","Time from the initial to final baseline crossing. This reflects the number of muscle fibers firing synchronously in the motor unit.")
B.HM=new A.f1("Amplitude","Peak-to-peak voltage measurement. Keep in mind, this is heavily dependent on how close your needle tip is to the firing fibers.")
B.HS=new A.f1("Phases","Baseline crossings plus one. A critical measure of synchrony.")
B.HJ=new A.f1("Initial Deflection","Is it positive (down) or negative (up)? Up is normal (endplate spikes) down means active denervation.")
B.HP=new A.f1("Shape","Are you seeing a brief spike (fibrillation) or a slow positive wave (PSW)?")
B.a2S=s([B.HR,B.HM,B.HS,B.HJ,B.HP],t.PZ)
B.HT=new A.mz("Morphology",B.a2S)
B.HF=new A.f1("Stable","The morphology remains completely consistent from firing to firing.")
B.HQ=new A.f1("Waxing/Waning","Amplitude changes smoothly over time. Think 'dive bomber' \u2013 classic myotonia.")
B.HL=new A.f1("Decrementing","A progressive, steady decrease in amplitude.")
B.HG=new A.f1("Abrupt Changes","Discrete jumps in morphology, often suggesting unstable neuromuscular transmission.")
B.HH=new A.f1("Blocking","Intermittent failure of a muscle fiber to fire. You'll see the wave occasionally drop an entire phase.")
B.a21=s([B.HF,B.HQ,B.HL,B.HG,B.HH],t.PZ)
B.HV=new A.mz("Stability",B.a21)
B.HN=new A.f1("Rate","Ranges from very slow (<2Hz, like fasciculations) to extremely fast (>100Hz, like myotonia).")
B.HO=new A.f1("Pattern","Is it perfectly regular (CRDs), irregular (fibrillations), or bursting (myokymia)?")
B.HK=new A.f1("Rhythm","Distinguish between a semi-rhythmic 'rain on a tin roof' vs. perfectly regular 'machine-like' firing.")
B.HI=new A.f1("Recruitment","Observe how units activate with increasing force. Does the rate go up, or do more units jump in?")
B.HE=new A.f1("Voluntary Control","Remember this pearl: Nobody has voluntary control under 4-5Hz. If it's firing at 2Hz, it's spontaneous.")
B.ZK=s([B.HN,B.HO,B.HK,B.HI,B.HE],t.PZ)
B.HU=new A.mz("Firing Characteristics",B.ZK)
B.a2y=s([B.HT,B.HV,B.HU],A.ad("q<mz>"))
