B.a1w=s(["EMG timeline","Myotomal patterns","Non-mechanical causes","Reflex associations"],t.s)
B.abG=new A.bY("What does the 'HI MADAM' mnemonic help remember?",B.a1w,2,"'HI MADAM' covers non-mechanical causes like Herpes, Inflammatory, Metastasis, Arachnoiditis, Diabetes, Abscess, and Mass.")
