c0=A.a([A.al(!0,"2.2","Marked Distal Latency Delay",w1,w9,p1),A.al(!0,"1.8","Slowing & Temporal Dispersion","18.2",x0,"22"),A.al(!0,l0,f0,"9.8",r3,p1),A.al(!0,"0.4","Conduction Block/Dispersion","24.5",ac2,q1)],o)
